- C: [Reverse Conditional] Reverse Conditional: It can be inferred that declining parrotfish populations must have been … cannot be proven solely from the premises given.', NULL, 'Information and Ideas', 'Inferences', 'reading_writing', 'information', 'INF', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"rw_subtype":"implication","dsat_blueprint_v1":true,"rw_format":"passage_mc","explanation_v2":true,"generator":"regenerate-english-fresh.mjs","master_manual_section":7,"regen_phase2":true,"regen_at":"2026-06-13T22:21:16.959Z","regen_seed_offset":100000}'::jsonb, now(), now());
